def _base32_decode(secret: str) -> bytes:
    normalized = secret.strip().replace(" ", "").upper()
    padding = "=" * ((8 - len(normalized) % 8) % 8)
    return base64.b32decode(normalized + padding, casefold=True)


def generate_totp_secret(length: int = 20) -> str:
    return base64.b32encode(secrets.token_bytes(length)).decode("utf-8").rstrip("=")


def hotp(secret: str, counter: int, digits: int = 6, algorithm: str = "SHA1") -> str:
    key = _base32_decode(secret)
    counter_bytes = struct.pack(">Q", counter)
    algo = algorithm.upper()
    if algo == "SHA1":
        digestmod = hashlib.sha1
    elif algo == "SHA256":
        digestmod = hashlib.sha256
    elif algo == "SHA512":
        digestmod = hashlib.sha512
    else:
        raise ValueError("Unsupported algorithm")

    hmac_hash = hmac.new(key, counter_bytes, digestmod).digest()
    offset = hmac_hash[-1] & 0x0F
    binary = struct.unpack(">I", hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
    otp = binary % (10 ** digits)
    return str(otp).zfill(digits)


def totp(
    secret: str,
    timestamp: int | None = None,
    interval: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
) -> str:
    if timestamp is None:
        timestamp = int(time.time())
    counter = int(timestamp // interval)
    return hotp(secret, counter, digits=digits, algorithm=algorithm)


def verify_totp(
    secret: str,
    code: str,
    timestamp: int | None = None,
    interval: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
    window: int = 1,
) -> bool:
    if timestamp is None:
        timestamp = int(time.time())

    code = str(code).strip()
    if not code.isdigit() or len(code) != digits:
        return False

    current_counter = int(timestamp // interval)
    for offset in range(-window, window + 1):
        expected = hotp(secret, current_counter + offset, digits=digits, algorithm=algorithm)
        if hmac.compare_digest(expected, code):
            return True
    return False


def build_otpauth_uri(
    secret: str,
    account_name: str,
    issuer: str,
    algorithm: str = "SHA1",
    digits: int = 6,
    period: int = 30,
) -> str:
    label = urllib.parse.quote(f"{issuer}:{account_name}")
    params = urllib.parse.urlencode(
        {
            "secret": secret,
            "issuer": issuer,
            "algorithm": algorithm.upper(),
            "digits": digits,
            "period": period,
        }
    )
    return f"otpauth://totp/{label}?{params}"


def generate_qr_code_base64(data: str) -> str:
    img = qrcode.make(data)
    buffer = BytesIO()
    img.save(buffer, format="PNG")
    return base64.b64encode(buffer.getvalue()).decode("utf-8")


